_G.update(_G2)
GLOSSARY = {k: v[0] for k, v in _G.items()}
CATEGORY = {k: v[1] for k, v in _G.items()}

# a few aliases (surface forms used in prose -> canonical key)
_ALIASES = {
    "p-values": "p-value", "confidence intervals": "confidence interval", "residuals": "residual",
    "outliers": "outlier", "confounders": "confounder", "confounding": "confounder",
    "colliders": "collider", "mediators": "mediator", "features": "feature", "thresholds": "threshold",
    "guardrail": "guardrail metric", "guardrails": "guardrail metric", "clt": "central limit theorem",
    "mde": "minimum detectable effect", "ctes": "cte", "windows function": "window function",
    "window functions": "window function", "joins": "join", "clusters": "clustering",
    "cluster": "clustering", "random forests": "random forest", "decision trees": "decision tree",
    "hyperparameters": "hyperparameter", "pipelines": "pipeline", "metrics": "primary metric",
    "z-score": "standardization", "auc": "roc-auc", "sensitivity": "recall",
    "underpowered": "power", "significance": "statistical significance",
}
for a, canon in _ALIASES.items():
    if canon in GLOSSARY:
        GLOSSARY.setdefault(a, GLOSSARY[canon])
        CATEGORY.setdefault(a, CATEGORY[canon])

def lookup(term):
    """Case-insensitive lookup; returns a definition string or None."""
    return GLOSSARY.get(term.strip().lower())
